import React from 'react';
import { Link } from 'react-router-dom';

const Navbar = () => {
  return (
    <nav style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem', background: '#333', color: '#fff' }}>
      <h2>FreelanceHub</h2>
      <div>
        <Link to="/" style={{ color: '#fff', margin: '0 10px', textDecoration: 'none' }}>Home</Link>
        <Link to="/jobs" style={{ color: '#fff', margin: '0 10px', textDecoration: 'none' }}>Jobs</Link>
        <Link to="/login" style={{ color: '#fff', margin: '0 10px', textDecoration: 'none' }}>Login</Link>
      </div>
    </nav>
  );
};

export default Navbar;
